mapper.insert:
/* 시스템 프롬프트 등록/수정 prompt.insertSystemPrompt */
INSERT INTO TB_PROMPT (
    PROMPT_ID
    , PROMPT_TYPE_CD
    , PROMPT_NAME
    , CONTENT
    , TEMPERATURE
    , TOP_P
    , APPLY_LLM_YN
    , APPLY_RAG_YN
    , APPLY_SQL_YN
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{promptId}
    , #{promptTypeCd, jdbcType=VARCHAR}
    , #{promptName, jdbcType=VARCHAR}
    , #{content, jdbcType=VARCHAR}
    , #{temperature, jdbcType=DOUBLE}
    , #{topP, jdbcType=DOUBLE}
    , #{applyLlmYn, jdbcType=VARCHAR}
    , #{applyRagYn, jdbcType=VARCHAR}
    , #{applySqlYn, jdbcType=VARCHAR}
    , #{useYn, jdbcType=VARCHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
    PROMPT_TYPE_CD = VALUES(PROMPT_TYPE_CD)
    , PROMPT_NAME = VALUES(PROMPT_NAME)
    , CONTENT = VALUES(CONTENT)
    , TEMPERATURE = VALUES(TEMPERATURE)
    , TOP_P = VALUES(TOP_P)
    , APPLY_LLM_YN = VALUES(APPLY_LLM_YN)
    , APPLY_RAG_YN = VALUES(APPLY_RAG_YN)
    , APPLY_SQL_YN = VALUES(APPLY_SQL_YN)
    , USE_YN = VALUES(USE_YN)
    , MODIFY_DT = NOW()

mapper.delete:
/* 시스템 프롬프트 삭제 prompt.deleteSystemPrompt */
DELETE FROM TB_PROMPT
WHERE PROMPT_ID = #{promptId}

mapper.insert:
/* 금지어 등록 prompt.insertBanWord */
INSERT INTO TB_BAN_WORD (
    WORD_ID
    , WORD
    , WORD_TYPE
    , USE_YN
    , CREATE_DT
) VALUES (
    #{wordId}
    , #{word, jdbcType=VARCHAR}
    , #{wordType, jdbcType=VARCHAR}
    , #{useYn, jdbcType=VARCHAR}
    , NOW()
)

mapper.update:
/* 콘텐츠 필터 정책 APPLY_YN 수정 prompt.updatePolicyApplyYn */
UPDATE TB_CONTENT_FLTR
SET APPLY_YN = #{applyYn}
    , MODIFY_DT = NOW()
WHERE FILTER_CD = #{filterCd}

mapper.insert:
/* 토큰 제한 설정 저장 prompt.insertTokenLmt */
INSERT INTO TB_TOKEN_LMT (
      LIMIT_ID
    , MAX_IN_TOKENS
    , MAX_OUT_TOKENS
    , CTXT_WIN
    , DAY_USER_LMT
    , MON_ORG_LMT
    , RATE_LMT_RPM
    , MIN_RESP_LEN
    , RESP_TMO
    , RETRY_CNT
    , STREAM_YN
    , MODIFY_DT
) VALUES (
      #{limitId}
    , #{maxInTokens, jdbcType=INTEGER}
    , #{maxOutTokens, jdbcType=INTEGER}
    , #{ctxtWin, jdbcType=INTEGER}
    , #{dayUserLmt, jdbcType=INTEGER}
    , #{monOrgLmt, jdbcType=INTEGER}
    , #{rateLmtRpm, jdbcType=INTEGER}
    , #{minRespLen, jdbcType=INTEGER}
    , #{respTmo, jdbcType=INTEGER}
    , #{retryCnt, jdbcType=INTEGER}
    , #{streamYn, jdbcType=VARCHAR}
    , NOW()
)
ON DUPLICATE KEY UPDATE
      MAX_IN_TOKENS = VALUES(MAX_IN_TOKENS)
    , MAX_OUT_TOKENS = VALUES(MAX_OUT_TOKENS)
    , CTXT_WIN = VALUES(CTXT_WIN)
    , DAY_USER_LMT = VALUES(DAY_USER_LMT)
    , MON_ORG_LMT = VALUES(MON_ORG_LMT)
    , RATE_LMT_RPM = VALUES(RATE_LMT_RPM)
    , MIN_RESP_LEN = VALUES(MIN_RESP_LEN)
    , RESP_TMO = VALUES(RESP_TMO)
    , RETRY_CNT = VALUES(RETRY_CNT)
    , STREAM_YN = VALUES(STREAM_YN)
    , MODIFY_DT = NOW()
